@giuseppe PTAL, We are seeing random flakes, we believe caused by this code.  Do you know if it is necessary.
Basically we are seeing file descriptors like boltdb database being closed when this code runs.

@edsantiago @mheon PTAL

could you check if the following patch has the same effect?

```
diff --git a/libpod/oci_conmon_linux.go b/libpod/oci_conmon_linux.go
index bd6af5281..48cf02749 100644
--- a/libpod/oci_conmon_linux.go
+++ b/libpod/oci_conmon_linux.go
@@ -954,9 +954,12 @@ func (r *ConmonOCIRuntime) createOCIContainer(ctr *Container, restoreOptions *Co
                return err
        }

+       var filesToClose []*os.File
        if ctr.config.PreserveFDs > 0 {
                for fd := 3; fd < int(3+ctr.config.PreserveFDs); fd++ {
-                       cmd.ExtraFiles = append(cmd.ExtraFiles, os.NewFile(uintptr(fd), fmt.Sprintf("fd-%d", fd)))
+                       f := os.NewFile(uintptr(fd), fmt.Sprintf("fd-%d", fd))
+                       filesToClose = append(filesToClose, f)
+                       cmd.ExtraFiles = append(cmd.ExtraFiles, f)
                }
        }

@@ -1052,14 +1055,10 @@ func (r *ConmonOCIRuntime) createOCIContainer(ctr *Container, restoreOptions *Co
                }
        }

-       if ctr.config.PreserveFDs > 0 {
-               for fd := 3; fd < int(3+ctr.config.PreserveFDs); fd++ {
-                       // These fds were passed down to the runtime.  Close them
-                       // and not interfere
-                       if err := os.NewFile(uintptr(fd), fmt.Sprintf("fd-%d", fd)).Close(); err != nil {
-                               logrus.Debugf("unable to close file fd-%d", fd)
-                       }
-               }
+       // These fds were passed down to the runtime.  Close them
+       // and not interfere
+       for _, f := range filesToClose {
+               errorhandling.CloseQuiet(f)
        }
```

if it works fine for you, please feel free to amend it in your PR.  I think libpod/oci_conmon_exec_linux.go needs the same fix.
